// Generated by OrchestKit Claude Plugin

// Guards the orank "NLWeb streaming support" recovery: POST /ask must switch to
// SSE (text/event-stream) when the client signals streaming via the RFC 7240
// `Prefer` header, in addition to the existing ?streaming / body / Accept paths.
// doc-search is mocked so the test isolates the streaming-trigger logic.

import { describe, expect, it, vi } from "vitest";

vi.mock("@/lib/doc-search", () => ({
	searchDocs: () => [
		{ id: "x", title: "OrchestKit", url: "/docs/overview", content: "c" },
	],
}));

import { GET, POST } from "@/app/api/ask/route";

function askReq(headers: Record<string, string>): Request {
	return new Request("https://orchestkit.yonyon.ai/ask", {
		method: "POST",
		headers: { "content-type": "application/json", ...headers },
		body: JSON.stringify({ query: "what is orchestkit" }),
	});
}

describe("/ask streaming triggers", () => {
	it("Prefer: streaming → text/event-stream", async () => {
		const res = await POST(askReq({ prefer: "streaming" }));
		expect(res.headers.get("Content-Type")).toBe("text/event-stream; charset=utf-8");
	});

	it("Prefer: respond-async → text/event-stream", async () => {
		const res = await POST(askReq({ prefer: "respond-async" }));
		expect(res.headers.get("Content-Type")).toBe("text/event-stream; charset=utf-8");
	});

	it("no streaming signal → JSON with _meta", async () => {
		const res = await POST(askReq({}));
		expect(res.headers.get("Content-Type")).toContain("application/json");
		const body = await res.json();
		expect(body._meta).toBeTruthy();
		expect(body._meta.version).toBeDefined();
	});
});

// A bare probe (no `query`) must return a 200 NLWeb envelope, not a 400 — a 400
// reads to agent-readiness scanners as "no NLWeb endpoint here".
describe("/ask no-query probe → 200 NLWeb envelope", () => {
	it("GET /ask with no query → 200, empty results, usage hint", async () => {
		const res = await GET(new Request("https://orchestkit.yonyon.ai/ask"));
		expect(res.status).toBe(200);
		expect(res.headers.get("Content-Type")).toContain("application/json");
		const body = await res.json();
		expect(body.results).toEqual([]);
		expect(body._meta.response_type).toBe("list");
		expect(body._meta.version).toBeDefined();
		expect(body._meta.count).toBe(0);
		expect(typeof body._meta.usage).toBe("string");
		expect(body._meta.usage.length).toBeGreaterThan(0);
	});

	it("POST /ask with empty query → 200, empty results", async () => {
		const res = await POST(
			new Request("https://orchestkit.yonyon.ai/ask", {
				method: "POST",
				headers: { "content-type": "application/json" },
				body: JSON.stringify({ query: "   " }),
			}),
		);
		expect(res.status).toBe(200);
		const body = await res.json();
		expect(body.results).toEqual([]);
		expect(body._meta.count).toBe(0);
		expect(typeof body._meta.usage).toBe("string");
	});

	it("POST /ask with an unreadable body → 200 envelope, not 400", async () => {
		const res = await POST(
			new Request("https://orchestkit.yonyon.ai/ask", {
				method: "POST",
				headers: { "content-type": "application/json" },
				body: "{ not json",
			}),
		);
		expect(res.status).toBe(200);
		const body = await res.json();
		expect(body.results).toEqual([]);
	});
});

// NLWeb's canonical request body is { query: { text: "..." } } — the shape
// agent-readiness scanners (orank) actually probe with. The route previously
// read `query` as a string and 500'd on the object form, which the scanner read
// as "no /ask endpoint found".
describe("/ask NLWeb canonical body { query: { text } }", () => {
	function nlwebReq(headers: Record<string, string> = {}): Request {
		return new Request("https://orchestkit.yonyon.ai/ask", {
			method: "POST",
			headers: { "content-type": "application/json", ...headers },
			body: JSON.stringify({ query: { text: "what is orchestkit" } }),
		});
	}

	it("POST with query.text → 200 JSON with _meta + results (not 500)", async () => {
		const res = await POST(nlwebReq());
		expect(res.status).toBe(200);
		expect(res.headers.get("Content-Type")).toContain("application/json");
		const body = await res.json();
		expect(body._meta.response_type).toBeDefined();
		expect(body._meta.version).toBeDefined();
		expect(body.results.length).toBeGreaterThan(0);
	});

	it("query.text + Accept: text/event-stream → SSE (streaming check)", async () => {
		const res = await POST(nlwebReq({ accept: "text/event-stream" }));
		expect(res.headers.get("Content-Type")).toBe(
			"text/event-stream; charset=utf-8",
		);
	});
});
